using ByteForge.Toolkit;

// Create a binary search tree for integers
var bst = new BinarySearchTree<int>();

// Insert values
bst.Insert(50);
bst.Insert(30);
bst.Insert(70);
bst.Insert(20);
bst.Insert(40);
bst.Insert(60);
bst.Insert(80);

Console.WriteLine($"Tree size: {bst.Count}");

// Search for values
bool contains40 = bst.Contains(40);  // true
bool contains90 = bst.Contains(90);  // false
Console.WriteLine($"Contains 40: {contains40}");
Console.WriteLine($"Contains 90: {contains90}");

// Find min and max values
int minValue = bst.FindMin();  // 20
int maxValue = bst.FindMax();  // 80
Console.WriteLine($"Min value: {minValue}");
Console.WriteLine($"Max value: {maxValue}");

// In-order traversal (sorted order)
Console.WriteLine("In-order traversal:");
foreach (var value in bst.InOrderTraversal())
{
    Console.Write($"{value} ");  // 20 30 40 50 60 70 80
}
Console.WriteLine();

// Remove values
bst.Remove(30);
bst.Remove(70);

Console.WriteLine($"After removal, tree size: {bst.Count}");
Console.WriteLine("Updated in-order traversal:");
foreach (var value in bst.InOrderTraversal())
{
    Console.Write($"{value} ");  // 20 40 50 60 80
}
Console.WriteLine();

public class Product : IComparable<Product>
{
    public int Id { get; set; }
    public string Name { get; set; }
    public decimal Price { get; set; }

    public int CompareTo(Product other)
    {
        if (other == null) return 1;
        return Price.CompareTo(other.Price);  // Sort by price
    }

    public override string ToString()
    {
        return $"{Name} (${Price:F2})";
    }
}

// Create BST for products sorted by price
var productTree = new BinarySearchTree<Product>();

// Add products
productTree.Insert(new Product { Id = 1, Name = "Laptop", Price = 999.99m });
productTree.Insert(new Product { Id = 2, Name = "Mouse", Price = 29.99m });
productTree.Insert(new Product { Id = 3, Name = "Keyboard", Price = 79.99m });
productTree.Insert(new Product { Id = 4, Name = "Monitor", Price = 299.99m });
productTree.Insert(new Product { Id = 5, Name = "Speakers", Price = 149.99m });

Console.WriteLine($"Product catalog has {productTree.Count} items");

// Find cheapest and most expensive products
var cheapest = productTree.FindMin();
var expensive = productTree.FindMax();
Console.WriteLine($"Cheapest: {cheapest}");
Console.WriteLine($"Most expensive: {expensive}");

// Display all products sorted by price
Console.WriteLine("\nProducts sorted by price:");
foreach (var product in productTree.InOrderTraversal())
{
    Console.WriteLine($"  {product}");
}

// Find products within a price range
var targetPrice = new Product { Price = 150m };  // Dummy product for comparison
var productsInRange = productTree.InOrderTraversal()
    .Where(p => p.Price >= 50m && p.Price <= 300m)
    .ToList();

Console.WriteLine("\nProducts in $50-$300 range:");
foreach (var product in productsInRange)
{
    Console.WriteLine($"  {product}");
}

// Performance test: BST vs List for sorted data
var random = new Random(12345); // Fixed seed for reproducible results
var testData = Enumerable.Range(1, 10000)
    .Select(i => random.Next(1, 100000))
    .ToArray();

// Test BST performance
var stopwatch = Stopwatch.StartNew();
var bst = new BinarySearchTree<int>();

foreach (var value in testData)
{
    bst.Insert(value);
}
stopwatch.Stop();
Console.WriteLine($"BST insertion of {testData.Length} items: {stopwatch.ElapsedMilliseconds}ms");

// Test search performance
stopwatch.Restart();
int foundCount = 0;
for (int i = 0; i < 1000; i++)
{
    if (bst.Contains(random.Next(1, 100000)))
        foundCount++;
}
stopwatch.Stop();
Console.WriteLine($"BST search 1000 times: {stopwatch.ElapsedMilliseconds}ms ({foundCount} found)");

// Test List performance for comparison
stopwatch.Restart();
var list = new List<int>(testData);
list.Sort();
stopwatch.Stop();
Console.WriteLine($"List sort of {testData.Length} items: {stopwatch.ElapsedMilliseconds}ms");

stopwatch.Restart();
foundCount = 0;
for (int i = 0; i < 1000; i++)
{
    if (list.BinarySearch(random.Next(1, 100000)) >= 0)
        foundCount++;
}
stopwatch.Stop();
Console.WriteLine($"List binary search 1000 times: {stopwatch.ElapsedMilliseconds}ms ({foundCount} found)");

// Display tree statistics
Console.WriteLine($"\nBST Statistics:");
Console.WriteLine($"  Total nodes: {bst.Count}");
Console.WriteLine($"  Tree height: {bst.Height}");
Console.WriteLine($"  Is balanced: {bst.IsBalanced()}");

// Bulk operations
var valuesToRemove = testData.Take(1000).ToArray();
stopwatch.Restart();
foreach (var value in valuesToRemove)
{
    bst.Remove(value);
}
stopwatch.Stop();
Console.WriteLine($"BST removal of {valuesToRemove.Length} items: {stopwatch.ElapsedMilliseconds}ms");
Console.WriteLine($"Remaining nodes: {bst.Count}");

using ByteForge.Toolkit;

// Parse a complex URL
string urlString = "https://api.example.com:8443/users/123?include=profile,preferences&format=json&v=2#section1";
var url = new Url(urlString);

Console.WriteLine($"Scheme: {url.Scheme}");           // https
Console.WriteLine($"Host: {url.Host}");               // api.example.com
Console.WriteLine($"Port: {url.Port}");               // 8443
Console.WriteLine($"Path: {url.Path}");               // /users/123
Console.WriteLine($"Query: {url.Query}");             // include=profile,preferences&format=json&v=2
Console.WriteLine($"Fragment: {url.Fragment}");       // section1

// Access query parameters
Console.WriteLine("\nQuery Parameters:");
foreach (var param in url.QueryParameters)
{
    Console.WriteLine($"  {param.Key}: {param.Value}");
}
// Output:
// include: profile,preferences
// format: json
// v: 2

// Get specific query parameter
string includeParam = url.GetQueryParameter("include");  // "profile,preferences"
string versionParam = url.GetQueryParameter("v");       // "2"
string missingParam = url.GetQueryParameter("missing"); // null

Console.WriteLine($"Include parameter: {includeParam}");
Console.WriteLine($"Version parameter: {versionParam}");
Console.WriteLine($"Missing parameter: {missingParam ?? "null"}");

// Check if parameter exists
bool hasFormat = url.HasQueryParameter("format");  // true
bool hasMissing = url.HasQueryParameter("missing"); // false

// Build URL step by step
var urlBuilder = new Url("https://api.example.com");
urlBuilder.SetPath("/search");
urlBuilder.SetQueryParameter("q", "laptop computers");
urlBuilder.SetQueryParameter("category", "electronics");
urlBuilder.SetQueryParameter("sort", "price");
urlBuilder.SetQueryParameter("order", "asc");
urlBuilder.SetQueryParameter("page", "1");
urlBuilder.SetQueryParameter("limit", "20");

string searchUrl = urlBuilder.ToString();
Console.WriteLine($"Search URL: {searchUrl}");
// https://api.example.com/search?q=laptop%20computers&category=electronics&sort=price&order=asc&page=1&limit=20

// Modify existing URL
var existingUrl = new Url("https://store.example.com/products?category=books&page=1");

// Update query parameters
existingUrl.SetQueryParameter("category", "electronics");
existingUrl.SetQueryParameter("page", "2");
existingUrl.SetQueryParameter("new_param", "value");

Console.WriteLine($"Modified URL: {existingUrl}");
// https://store.example.com/products?category=electronics&page=2&new_param=value

// Remove query parameters
existingUrl.RemoveQueryParameter("new_param");
Console.WriteLine($"After removal: {existingUrl}");
// https://store.example.com/products?category=electronics&page=2

// Clear all query parameters
existingUrl.ClearQueryParameters();
Console.WriteLine($"After clearing: {existingUrl}");
// https://store.example.com/products

// Build pagination URLs
var baseUrl = new Url("https://api.example.com/data");
baseUrl.SetQueryParameter("size", "50");

for (int page = 1; page <= 5; page++)
{
    var pageUrl = new Url(baseUrl.ToString()); // Copy base URL
    pageUrl.SetQueryParameter("page", page.ToString());
    Console.WriteLine($"Page {page}: {pageUrl}");
}

// Test various URL formats
var testUrls = new[]
{
    "https://example.com",
    "http://localhost:3000/api/users",
    "ftp://files.example.com/documents/file.pdf",
    "https://user:pass@secure.example.com:8443/private",
    "https://example.com/path/with%20spaces?param=value%20with%20spaces",
    "mailto:user@example.com",
    "file:///C:/Users/Documents/file.txt",
    "/relative/path?query=value",
    "?just=query&parameters=here",
    "invalid-url-format"
};

Console.WriteLine("URL Parsing Results:");
foreach (var urlString in testUrls)
{
    try
    {
        var url = new Url(urlString);
        Console.WriteLine($"✓ {urlString}");
        Console.WriteLine($"  Scheme: {url.Scheme ?? "none"}");
        Console.WriteLine($"  Host: {url.Host ?? "none"}");
        Console.WriteLine($"  Port: {(url.Port > 0 ? url.Port.ToString() : "default")}");
        Console.WriteLine($"  Path: {url.Path ?? "none"}");

        if (url.QueryParameters.Count > 0)
        {
            Console.WriteLine($"  Query params: {url.QueryParameters.Count}");
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"✗ {urlString}");
        Console.WriteLine($"  Error: {ex.Message}");
    }
    Console.WriteLine();
}

// URL comparison and equality
var url1 = new Url("https://example.com/path?a=1&b=2");
var url2 = new Url("https://example.com/path?b=2&a=1");  // Same params, different order
var url3 = new Url("https://example.com/path?a=1&b=2&c=3");

Console.WriteLine("URL Comparisons:");
Console.WriteLine($"URL1: {url1}");
Console.WriteLine($"URL2: {url2}");
Console.WriteLine($"URL3: {url3}");
Console.WriteLine($"URL1 equals URL2: {url1.Equals(url2)}");
Console.WriteLine($"URL1 equals URL3: {url1.Equals(url3)}");

// URL encoding/decoding
var urlWithSpecialChars = new Url("https://search.example.com");
urlWithSpecialChars.SetQueryParameter("q", "hello world & special chars!");
urlWithSpecialChars.SetQueryParameter("filter", "price>100 AND category='electronics'");

Console.WriteLine($"\nURL with encoded parameters:");
Console.WriteLine(urlWithSpecialChars.ToString());

// Retrieve decoded parameters
string query = urlWithSpecialChars.GetQueryParameter("q");
string filter = urlWithSpecialChars.GetQueryParameter("filter");
Console.WriteLine($"Decoded query: {query}");
Console.WriteLine($"Decoded filter: {filter}");

using ByteForge.Toolkit;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

// Advanced caching system using binary search tree and URL utilities
public class ApiCacheService
{
    private readonly BinarySearchTree<CacheEntry> _cacheByExpiry;
    private readonly Dictionary<string, CacheEntry> _cacheByKey;
    private readonly object _lockObject = new object();
    private readonly Timer _cleanupTimer;

    public int MaxCacheSize { get; set; } = 10000;
    public TimeSpan DefaultTtl { get; set; } = TimeSpan.FromMinutes(30);

    public ApiCacheService()
    {
        _cacheByExpiry = new BinarySearchTree<CacheEntry>();
        _cacheByKey = new Dictionary<string, CacheEntry>();

        // Setup periodic cleanup
        _cleanupTimer = new Timer(CleanupExpiredEntries, null, 
            TimeSpan.FromMinutes(1), TimeSpan.FromMinutes(1));
    }

    public void Store(string url, object data, TimeSpan? ttl = null)
    {
        var normalizedUrl = NormalizeUrl(url);
        var entry = new CacheEntry
        {
            Key = normalizedUrl,
            Data = data,
            ExpiryTime = DateTime.UtcNow.Add(ttl ?? DefaultTtl),
            AccessCount = 0,
            LastAccessed = DateTime.UtcNow
        };

        lock (_lockObject)
        {
            // Remove existing entry if present
            if (_cacheByKey.TryGetValue(normalizedUrl, out var existing))
            {
                _cacheByExpiry.Remove(existing);
            }

            // Add new entry
            _cacheByKey[normalizedUrl] = entry;
            _cacheByExpiry.Insert(entry);

            // Enforce cache size limit
            EnforceCacheSizeLimit();
        }
    }

    public T Get<T>(string url) where T : class
    {
        var normalizedUrl = NormalizeUrl(url);

        lock (_lockObject)
        {
            if (_cacheByKey.TryGetValue(normalizedUrl, out var entry))
            {
                // Check if expired
                if (DateTime.UtcNow > entry.ExpiryTime)
                {
                    RemoveEntry(entry);
                    return null;
                }

                // Update access statistics
                entry.AccessCount++;
                entry.LastAccessed = DateTime.UtcNow;

                return entry.Data as T;
            }
        }

        return null;
    }

    public bool Contains(string url)
    {
        var normalizedUrl = NormalizeUrl(url);

        lock (_lockObject)
        {
            if (_cacheByKey.TryGetValue(normalizedUrl, out var entry))
            {
                if (DateTime.UtcNow <= entry.ExpiryTime)
                {
                    return true;
                }
                else
                {
                    RemoveEntry(entry);
                }
            }
        }

        return false;
    }

    public void Remove(string url)
    {
        var normalizedUrl = NormalizeUrl(url);

        lock (_lockObject)
        {
            if (_cacheByKey.TryGetValue(normalizedUrl, out var entry))
            {
                RemoveEntry(entry);
            }
        }
    }

    private string NormalizeUrl(string url)
    {
        try
        {
            var urlObj = new Url(url);

            // Normalize the URL for consistent caching
            // - Convert to lowercase
            // - Sort query parameters
            // - Remove fragment

            var normalizedUrl = new Url($"{urlObj.Scheme?.ToLower()}://{urlObj.Host?.ToLower()}");

            if (urlObj.Port > 0 && !IsDefaultPort(urlObj.Scheme, urlObj.Port))
            {
                normalizedUrl = new Url($"{normalizedUrl}:{urlObj.Port}");
            }

            if (!string.IsNullOrEmpty(urlObj.Path))
            {
                normalizedUrl.SetPath(urlObj.Path);
            }

            // Sort query parameters for consistent caching
            var sortedParams = urlObj.QueryParameters
                .OrderBy(kvp => kvp.Key)
                .ThenBy(kvp => kvp.Value);

            foreach (var param in sortedParams)
            {
                normalizedUrl.SetQueryParameter(param.Key, param.Value);
            }

            return normalizedUrl.ToString();
        }
        catch
        {
            // If URL parsing fails, return original
            return url;
        }
    }

    private bool IsDefaultPort(string scheme, int port)
    {
        return scheme?.ToLower() switch
        {
            "http" => port == 80,
            "https" => port == 443,
            "ftp" => port == 21,
            _ => false
        };
    }

    private void RemoveEntry(CacheEntry entry)
    {
        _cacheByKey.Remove(entry.Key);
        _cacheByExpiry.Remove(entry);
    }

    private void EnforceCacheSizeLimit()
    {
        while (_cacheByKey.Count > MaxCacheSize)
        {
            // Remove least recently accessed entry
            var oldestEntry = _cacheByKey.Values
                .OrderBy(e => e.LastAccessed)
                .First();

            RemoveEntry(oldestEntry);
        }
    }

    private void CleanupExpiredEntries(object state)
    {
        var now = DateTime.UtcNow;
        var expiredEntries = new List<CacheEntry>();

        lock (_lockObject)
        {
            // Find all expired entries
            foreach (var entry in _cacheByKey.Values)
            {
                if (now > entry.ExpiryTime)
                {
                    expiredEntries.Add(entry);
                }
            }

            // Remove expired entries
            foreach (var entry in expiredEntries)
            {
                RemoveEntry(entry);
            }
        }

        if (expiredEntries.Count > 0)
        {
            Console.WriteLine($"Cleaned up {expiredEntries.Count} expired cache entries");
        }
    }

    public CacheStatistics GetStatistics()
    {
        lock (_lockObject)
        {
            var now = DateTime.UtcNow;
            var validEntries = _cacheByKey.Values
                .Where(e => now <= e.ExpiryTime)
                .ToList();

            return new CacheStatistics
            {
                TotalEntries = validEntries.Count,
                ExpiredEntries = _cacheByKey.Count - validEntries.Count,
                AverageAccessCount = validEntries.Average(e => e.AccessCount),
                OldestEntry = validEntries.OrderBy(e => e.LastAccessed).FirstOrDefault()?.LastAccessed,
                NewestEntry = validEntries.OrderByDescending(e => e.LastAccessed).FirstOrDefault()?.LastAccessed,
                TreeHeight = _cacheByExpiry.Height,
                IsTreeBalanced = _cacheByExpiry.IsBalanced()
            };
        }
    }

    public void Clear()
    {
        lock (_lockObject)
        {
            _cacheByKey.Clear();
            _cacheByExpiry.Clear();
        }
    }

    public void Dispose()
    {
        _cleanupTimer?.Dispose();
        Clear();
    }
}

public class CacheEntry : IComparable<CacheEntry>
{
    public string Key { get; set; }
    public object Data { get; set; }
    public DateTime ExpiryTime { get; set; }
    public long AccessCount { get; set; }
    public DateTime LastAccessed { get; set; }

    // Compare by expiry time for BST ordering
    public int CompareTo(CacheEntry other)
    {
        if (other == null) return 1;

        int result = ExpiryTime.CompareTo(other.ExpiryTime);
        if (result == 0)
        {
            // If expiry times are equal, compare by key to ensure uniqueness
            result = string.Compare(Key, other.Key, StringComparison.OrdinalIgnoreCase);
        }
        return result;
    }

    public override bool Equals(object obj)
    {
        return obj is CacheEntry other && Key.Equals(other.Key, StringComparison.OrdinalIgnoreCase);
    }

    public override int GetHashCode()
    {
        return Key?.ToLowerInvariant().GetHashCode() ?? 0;
    }
}

public class CacheStatistics
{
    public int TotalEntries { get; set; }
    public int ExpiredEntries { get; set; }
    public double AverageAccessCount { get; set; }
    public DateTime? OldestEntry { get; set; }
    public DateTime? NewestEntry { get; set; }
    public int TreeHeight { get; set; }
    public bool IsTreeBalanced { get; set; }
}

// API service that uses the cache
public class ApiService
{
    private readonly ApiCacheService _cache;
    private readonly HttpClient _httpClient;

    public ApiService()
    {
        _cache = new ApiCacheService
        {
            MaxCacheSize = 5000,
            DefaultTtl = TimeSpan.FromMinutes(15)
        };
        _httpClient = new HttpClient();
    }

    public async Task<T> GetAsync<T>(string url) where T : class
    {
        // Try cache first
        var cachedData = _cache.Get<T>(url);
        if (cachedData != null)
        {
            Console.WriteLine($"Cache hit for: {url}");
            return cachedData;
        }

        Console.WriteLine($"Cache miss for: {url}");

        // Fetch from API
        try
        {
            var response = await _httpClient.GetStringAsync(url);
            var data = System.Text.Json.JsonSerializer.Deserialize<T>(response);

            // Store in cache
            _cache.Store(url, data);

            return data;
        }
        catch (Exception ex)
        {
            Console.WriteLine($"API call failed for {url}: {ex.Message}");
            return null;
        }
    }

    public async Task DemonstrateUsage()
    {
        Console.WriteLine("API Cache Service Demonstration");
        Console.WriteLine("===============================");

        // Test URLs with various formats
        var testUrls = new[]
        {
            "https://api.example.com/users?page=1&size=10",
            "https://api.example.com/users?size=10&page=1",  // Same as above, different param order
            "https://api.example.com/users?page=1&size=10&sort=name",
            "https://api.example.com/products?category=electronics",
            "https://api.example.com/orders?status=pending&date=2024-01-15",
        };

        // Simulate API calls
        foreach (var url in testUrls)
        {
            // First call - should be cache miss
            var data1 = await GetAsync<object>(url);

            // Second call - should be cache hit
            var data2 = await GetAsync<object>(url);

            Console.WriteLine($"  Contains in cache: {_cache.Contains(url)}");
            Console.WriteLine();
        }

        // Display cache statistics
        var stats = _cache.GetStatistics();
        Console.WriteLine("Cache Statistics:");
        Console.WriteLine($"  Total entries: {stats.TotalEntries}");
        Console.WriteLine($"  Expired entries: {stats.ExpiredEntries}");
        Console.WriteLine($"  Average access count: {stats.AverageAccessCount:F2}");
        Console.WriteLine($"  Tree height: {stats.TreeHeight}");
        Console.WriteLine($"  Tree balanced: {stats.IsTreeBalanced}");

        if (stats.OldestEntry.HasValue && stats.NewestEntry.HasValue)
        {
            var age = stats.NewestEntry.Value - stats.OldestEntry.Value;
            Console.WriteLine($"  Cache age span: {age.TotalMinutes:F1} minutes");
        }

        // Test URL normalization
        Console.WriteLine("\nURL Normalization Test:");
        var urlVariations = new[]
        {
            "https://API.EXAMPLE.COM/users?b=2&a=1",
            "https://api.example.com:443/users?a=1&b=2",
            "https://api.example.com/users?a=1&b=2#section",
        };

        foreach (var url in urlVariations)
        {
            var contains = _cache.Contains(url);
            Console.WriteLine($"  {url} -> {(contains ? "Found" : "Not found")}");
        }
    }

    public void Dispose()
    {
        _cache?.Dispose();
        _httpClient?.Dispose();
    }
}

// Main program
public class Program
{
    static async Task Main(string[] args)
    {
        var apiService = new ApiService();

        try
        {
            await apiService.DemonstrateUsage();
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Error: {ex.Message}");
        }
        finally
        {
            apiService.Dispose();
        }
    }
}
